// Simulate a slowly oscillating PV around the setpoint
var t = Date.now() / 12000;
var pv = 47.2 + 3 * Math.sin(t);
var alarmState = pv > 49.8 ? 'UNACK' : 'NORMAL';
msg.payload = {
    pv:        Math.round(pv * 10) / 10,
    sp:        50.0,
    mode:      'AUTO',
    status:    alarmState === 'NORMAL' ? 'RUNNING' : 'TRIPPED',
    interlock: false,
    interlocks: [],
    permissives: [
        { id: 'loop-healthy', label: 'Loop healthy', ok: true }
    ],
    alarm: {
        state: alarmState,
        priority: alarmState === 'NORMAL' ? 'LOW' : 'HIGH',
        message: alarmState === 'NORMAL' ? '' : 'PV high',
        active: alarmState !== 'NORMAL',
        source: 'TIC-101.PV'
    }
};
return msg;
